INSERT INTO `doctor_infor` VALUES (1,5,2,2,'PRI4','PRO1','PAY3','123 Trung vương','Phòng khám Spinetech Clinic','Không có ',0,'2026-04-02 05:46:15','2026-04-06 17:37:05','<h2><strong>PGS. TS. BSCK II. TTƯT Vũ Văn Hòe</strong></h2>\n<ul>\n<li>Bác sĩ có 35 năm kinh nghiệm về vực Cột sống, thần kinh, cơ xương khớp</li>\n<li>Phó chủ tịch hội Phẫu thuật cột sống Việt Nam</li>\n<li>Bác sĩ nhận khám từ 7 tuổi trở lên</li>\n</ul>\n<p><strong>Nhận khám và điều trị</strong></p>\n<ul>\n<li>Các bệnh lý về cột sống</li>\n<li>Các bệnh lý liên quan đến thần kinh</li>\n<li>Các bệnh lý liên quan đến cơ xương khớp</li>\n</ul>\n<p><strong>Quá trình công tác</strong></p>\n<ul>\n<li>Bộ môn Khoa Phẫu thuật thần kinh, Bệnh viện Quân y 103, Học viện Quân Y</li>\n<li>Nguyên Chủ nhiệm Bộ môn kiêm Chủ nhiệm Khoa</li>\n</ul>\n<p><strong>Quá trình đào tạo</strong></p>\n<ul>\n<li>Bác sĩ Chuyên khoa cấp II, Học viện Quân y (2010 - 2011)</li>\n<li>Tiến sỹ Y khoa, Hệ chính qui, Học viện Quân y (1996 - 2000)</li>\n<li>Cao học Phẫu thuật thần kinh, Hệ chính qui, Học viện Quân y (1993 - 1995)</li>\n<li>Bác sĩ Đa khoa, Hệ chính qui, Học viện Quân y (1982 - 1988)</li>\n<li>Đào tạo về vi phẫu thần kinh tại Fujita Health University Hospital, Nhật Bản. Tham dự nhiều khóa tập huấn kỹ thuật và các hội nghị quốc tế chuyên ngành tại các nước Mỹ, Pháp, Đức, Áo, Hàn Quốc, Singapore, Thái Lan, Philipine,…</li>\n</ul>\n<p><strong>Thành viên các Hội khoa học, tổ chức chuyên môn</strong></p>\n<ul>\n<li>Phó chủ tịch hội Phẫu thuật Cột sống Việt Nam</li>\n<li>Ủy viên Ban chấp hành hội Phẫu thuật thần kinh Việt Nam</li>\n</ul>\n<p><strong>Giải thưởng</strong></p>\n<ul>\n<li>Được tặng danh hiệu Thầy thuốc ưu tú (02/2014)</li>\n<li>Được công nhận đạt chuẩn chức danh Phó giáo sư (10/2011)</li>\n</ul>\n','## **PGS. TS. BSCK II. TTƯT Vũ Văn Hòe**\n\n- Bác sĩ có 35 năm kinh nghiệm về vực Cột sống, thần kinh, cơ xương khớp\n- Phó chủ tịch hội Phẫu thuật cột sống Việt Nam\n- Bác sĩ nhận khám từ 7 tuổi trở lên\n\n **Nhận khám và điều trị**\n\n- Các bệnh lý về cột sống\n- Các bệnh lý liên quan đến thần kinh\n- Các bệnh lý liên quan đến cơ xương khớp\n\n**Quá trình công tác**\n\n- Bộ môn Khoa Phẫu thuật thần kinh, Bệnh viện Quân y 103, Học viện Quân Y\n- Nguyên Chủ nhiệm Bộ môn kiêm Chủ nhiệm Khoa\n\n **Quá trình đào tạo**\n\n- Bác sĩ Chuyên khoa cấp II, Học viện Quân y (2010 - 2011)\n- Tiến sỹ Y khoa, Hệ chính qui, Học viện Quân y (1996 - 2000)\n- Cao học Phẫu thuật thần kinh, Hệ chính qui, Học viện Quân y (1993 - 1995)\n- Bác sĩ Đa khoa, Hệ chính qui, Học viện Quân y (1982 - 1988)\n- Đào tạo về vi phẫu thần kinh tại Fujita Health University Hospital, Nhật Bản. Tham dự nhiều khóa tập huấn kỹ thuật và các hội nghị quốc tế chuyên ngành tại các nước Mỹ, Pháp, Đức, Áo, Hàn Quốc, Singapore, Thái Lan, Philipine,…\n\n **Thành viên các Hội khoa học, tổ chức chuyên môn**\n\n- Phó chủ tịch hội Phẫu thuật Cột sống Việt Nam\n- Ủy viên Ban chấp hành hội Phẫu thuật thần kinh Việt Nam\n\n **Giải thưởng**\n\n- Được tặng danh hiệu Thầy thuốc ưu tú (02/2014)\n- Được công nhận đạt chuẩn chức danh Phó giáo sư (10/2011)','Bác sĩ có 35 năm kinh nghiệm về vực Cột sống, thần kinh, cơ xương khớp\nPhó chủ tịch hội Phẫu thuật cột sống Việt Nam \nBác sĩ nhận khám từ 7 tuổi trở lên \n'),(2,6,1,2,'PRI5','PRO1','PAY3','TT20 - 21 - 22, Số 204 Nguyễn Tuân, Phường Thanh Xuân, TP Hà Nội','Hệ thống y Tế Thu Cúc','Hỗ trợ bảo hiểm',0,'2026-04-05 15:35:35','2026-04-05 15:54:40','<p><strong>Nhận khám và điều trị</strong></p>\n<ul>\n<li>\n<p>Viêm cột sống dính khớp: Viêm khớp cùng chậu, viêm khớp ngoại vi, đau và sưng ở khớp háng và khớp gối</p>\n</li>\n<li>\n<p>Viêm khớp dạng thấp: Khớp sưng, nóng, đỏ, đau dai dẳng. Các dấu hiệu này hầu hết xuất hiện đối xứng ở hai bên cơ thể (hai bên tay, cổ tay, đầu gối,...)</p>\n</li>\n<li>\n<p>Thoái khớp gối, khớp vai: Khô khớp, cứng khớp, lục khục, mất ngủ, teo cơ, sưng tấy, Đau, giảm tầm vận động, hạn chế di chuyển của khớp</p>\n</li>\n<li>\n<p>Thoái hóa cột sống thắt lưng</p>\n</li>\n<li>\n<p>Thoát vị đĩa đệm</p>\n</li>\n<li>\n<p>Loãng xương</p>\n</li>\n<li>\n<p>Gút</p>\n</li>\n<li>\n<p>Viêm khớp</p>\n</li>\n<li>\n<p>Siêu âm đánh giá các tổn thương cơ xương khớp</p>\n</li>\n<li>\n<p>Thực hiện các thủ thuật điều trị: Tiêm khớp, tiêm khớp dưới hướng dẫn siêu âm, tiêm huyết tương giàu tiểu cầu,...</p>\n</li>\n</ul>\n<p><strong>Quá trình công tác</strong></p>\n<ul>\n<li>\n<p>Bác sĩ chuyên khoa Cơ Xương Khớp, Phòng khám Đa khoa MSC (Nay)</p>\n</li>\n<li>\n<p>Phó Trưởng Khoa Cơ Xương Khớp, Bệnh viện E (2019 - nay)</p>\n</li>\n<li>\n<p>Bác sĩ Điều trị tại Khoa Cơ Xương Khớp, Bệnh viện E (2009 - 2019)</p>\n</li>\n<li>\n<p>Giảng viên thỉnh giảng Bộ môn Nội Cơ Xương Khớp, Trường Đại học Y Dược Quốc Gia (2009 - 2019)</p>\n</li>\n<li>\n<p>Giảng viên các lớp đào tạo liên tục cho bác sĩ sau đại học, Bệnh viện E (2009 - 2019)</p>\n</li>\n</ul>\n<p><strong>Quá trình đào tạo</strong></p>\n<ul>\n<li>\n<p>Cao học chuyên ngành Nội khoa, Đại học Y Hà Nội (11/2013 - 12/2015)</p>\n</li>\n<li>\n<p>Đại học chuyên ngành Bác sĩ đa khoa, Học viện Quân Y (07/2003 - 07/2009)</p>\n</li>\n</ul>\n<p><strong>Chứng chỉ trong nước hoặc nước ngoài</strong></p>\n<ul>\n<li>\n<p>Sư phạm y học cơ bản cho giảng viên đào tạo liên tục, Trung tâm HMDP, Tổng hội y học Việt Nam (9/2022)</p>\n</li>\n<li>\n<p>Tham gia giảng dạy khóa học: “Chẩn đoán và điều trị bệnh lý cơ xương khớp và tiêm khớp ngoại vi”, Bệnh viện E (6/2017)</p>\n</li>\n<li>\n<p>Định hướng chuyên ngành Cơ Xương Khớp, Bệnh viện Bạch Mai (2012)</p>\n</li>\n<li>\n<p>Đào tạo liên tục Phương pháp nghiên cứu khoa học dành cho bác sĩ, Bệnh viện E (11/2011)</p>\n</li>\n<li>\n<p>Siêu âm tổng quát, Đại học Y Hà Nội (2011)</p>\n</li>\n</ul>\n<p><strong>Sách và các công trình báo cáo khoa học</strong></p>\n<ul>\n<li>\n<p>Giảm viêm đa khớp gốc chi: Ca lâm sàng » (Mai Thị Minh Tâm, Nguyễn Trần Trung, Trịnh Việt Anh, Vũ Hồng Anh), trang 171, Tạp chí Y học Việt Nam tập 502 (Tháng 5/2021)</p>\n</li>\n<li>\n<p>Đánh giá tác dụng điều trị thoái hóa khớp gối nguyên phát của liệu pháp tiêm MD-Collagen: Nghiên cứu quan sát, một trung tâm » (Đặng Hồng Hoa, Nguyễn Trần Trung, Đặng Chí Hiếu) (Tháng 8/2020)</p>\n</li>\n<li>\n<p>Đánh giá kết quả sau 8 tuần điều trị bằng liệu pháp huyết tương giàu tiểu cầu tự thân ở bệnh nhân viêm lồi cầu ngoài xương cánh tay ». (Nguyễn Trần Trung, Đặng Hồng Hoa), trang 68, Y học thực hành ISSN (Số 4/2016)</p>\n</li>\n</ul>\n<p><strong>Thành viên các Hội khoa học, tổ chức chuyên môn</strong></p>\n<ul>\n<li>\n<p>Tham gia các lớp đào tạo quốc tế tại Pháp, Nhật, Thái Lan, Singapore, Việt Nam</p>\n</li>\n<li>\n<p>Thành viên Hội Thấp Khớp học Việt Nam</p>\n</li>\n<li>\n<p>Thành viên Hội Thấp Khớp học Hà Nội</p>\n</li>\n<li>\n<p>Thành viên hội thấp khớp học Châu Á Thái bình dương (APLAR)</p>\n</li>\n</ul>\n','**Nhận khám và điều trị**\n* Viêm cột sống dính khớp: Viêm khớp cùng chậu, viêm khớp ngoại vi, đau và sưng ở khớp háng và khớp gối\n\n* Viêm khớp dạng thấp: Khớp sưng, nóng, đỏ, đau dai dẳng. Các dấu hiệu này hầu hết xuất hiện đối xứng ở hai bên cơ thể (hai bên tay, cổ tay, đầu gối,...)\n\n* Thoái khớp gối, khớp vai: Khô khớp, cứng khớp, lục khục, mất ngủ, teo cơ, sưng tấy, Đau, giảm tầm vận động, hạn chế di chuyển của khớp\n\n* Thoái hóa cột sống thắt lưng\n\n* Thoát vị đĩa đệm\n\n* Loãng xương\n\n* Gút\n\n* Viêm khớp\n\n* Siêu âm đánh giá các tổn thương cơ xương khớp\n\n* Thực hiện các thủ thuật điều trị: Tiêm khớp, tiêm khớp dưới hướng dẫn siêu âm, tiêm huyết tương giàu tiểu cầu,...\n\n**Quá trình công tác**\n* Bác sĩ chuyên khoa Cơ Xương Khớp, Phòng khám Đa khoa MSC (Nay)\n\n* Phó Trưởng Khoa Cơ Xương Khớp, Bệnh viện E (2019 - nay)\n\n* Bác sĩ Điều trị tại Khoa Cơ Xương Khớp, Bệnh viện E (2009 - 2019)\n\n* Giảng viên thỉnh giảng Bộ môn Nội Cơ Xương Khớp, Trường Đại học Y Dược Quốc Gia (2009 - 2019)\n\n* Giảng viên các lớp đào tạo liên tục cho bác sĩ sau đại học, Bệnh viện E (2009 - 2019)\n\n**Quá trình đào tạo**\n* Cao học chuyên ngành Nội khoa, Đại học Y Hà Nội (11/2013 - 12/2015)\n\n* Đại học chuyên ngành Bác sĩ đa khoa, Học viện Quân Y (07/2003 - 07/2009)\n\n**Chứng chỉ trong nước hoặc nước ngoài**\n* Sư phạm y học cơ bản cho giảng viên đào tạo liên tục, Trung tâm HMDP, Tổng hội y học Việt Nam (9/2022)\n\n* Tham gia giảng dạy khóa học: “Chẩn đoán và điều trị bệnh lý cơ xương khớp và tiêm khớp ngoại vi”, Bệnh viện E (6/2017)\n\n* Định hướng chuyên ngành Cơ Xương Khớp, Bệnh viện Bạch Mai (2012)\n\n* Đào tạo liên tục Phương pháp nghiên cứu khoa học dành cho bác sĩ, Bệnh viện E (11/2011)\n\n* Siêu âm tổng quát, Đại học Y Hà Nội (2011)\n\n**Sách và các công trình báo cáo khoa học**\n* Giảm viêm đa khớp gốc chi: Ca lâm sàng » (Mai Thị Minh Tâm, Nguyễn Trần Trung, Trịnh Việt Anh, Vũ Hồng Anh), trang 171, Tạp chí Y học Việt Nam tập 502 (Tháng 5/2021)\n\n* Đánh giá tác dụng điều trị thoái hóa khớp gối nguyên phát của liệu pháp tiêm MD-Collagen: Nghiên cứu quan sát, một trung tâm » (Đặng Hồng Hoa, Nguyễn Trần Trung, Đặng Chí Hiếu) (Tháng 8/2020)\n\n* Đánh giá kết quả sau 8 tuần điều trị bằng liệu pháp huyết tương giàu tiểu cầu tự thân ở bệnh nhân viêm lồi cầu ngoài xương cánh tay ». (Nguyễn Trần Trung, Đặng Hồng Hoa), trang 68, Y học thực hành ISSN (Số 4/2016)\n\n**Thành viên các Hội khoa học, tổ chức chuyên môn**\n* Tham gia các lớp đào tạo quốc tế tại Pháp, Nhật, Thái Lan, Singapore, Việt Nam\n\n* Thành viên Hội Thấp Khớp học Việt Nam\n\n* Thành viên Hội Thấp Khớp học Hà Nội\n\n* Thành viên hội thấp khớp học Châu Á Thái bình dương (APLAR)','Bác sĩ có nhiều năm kinh nghiệm trong khám và điều trị Cơ xương khớp \nPhó trưởng khoa Cơ Xương Khớp Bệnh viện E\nBác sĩ nhận khám từ 15 tuổi trở lên '),(3,7,2,3,'PRI2','PRO1','PAY3','','','Không',0,'2026-04-07 10:21:04','2026-04-07 10:22:59','<p><strong>Thầy thuốc ưu tú, Tiến sĩ, Bác sĩ Nguyễn Văn Doanh</strong></p>\n<ul>\n<li>\n<p>Bác sĩ có 40 năm kinh nghiệm làm việc chuyên khoa Nội Thần kinh</p>\n</li>\n<li>\n<p>Bác sĩ điều trị hiệu quả các bệnh lý nội khoa, thần kinh phổ biến hiện nay như: đau nửa đầu, rối loạn tiền đình, các rối loạn giấc ngủ, các bệnh về sa sút trí tuệ, bệnh động kinh ở người lớn và trẻ em và nhiều bệnh lý thần kinh khác</p>\n</li>\n<li>\n<p>Nguyên chủ nhiệm khoa thần kinh, Bệnh viện Hữu Nghị Việt Xô</p>\n</li>\n</ul>\n<p><strong>Khám và điều trị</strong></p>\n<ul>\n<li>\n<p>Các bệnh đau đầu: Chứng đau nửa đầu, đau đầu căn nguyên mạch máu, đau đầu mạn tính hàng ngày,..</p>\n</li>\n<li>\n<p>Bệnh đau vai gáy do thoái hóa cột sống cổ, thoát vị đĩa đệm cột sống cổ, …</p>\n</li>\n<li>\n<p>Đau thắt lưng hông do thoái hóa, thoát vị, đau do viêm khớp cùng chậu…</p>\n</li>\n<li>\n<p>Rối loạn tiền đình</p>\n</li>\n<li>\n<p>Điều trị chóng mặt do thiếu máu não</p>\n</li>\n<li>\n<p>Tư vấn và điều trị các bệnh lý rối loạn về giấc ngủ: mất ngủ cấp tính hoặc mạn tính</p>\n</li>\n<li>\n<p>Liệt dây 7 ngoại vi: Viêm các dây thần kinh sọ não và các dây thần kinh ngoại vi khác như hội chứng ống cổ tay, đau vai khuỷu tay do chơi thể thao</p>\n</li>\n<li>\n<p>Liệt nửa người do nhồi máu não</p>\n</li>\n<li>\n<p>Các bệnh lý về sa sút trí tuệ: Suy giảm nhận thức nhẹ, suy giảm trí nhớ, sa sút trí tuệ nguyên nhân mạch máu (sa sút trí tuệ sau đột quỵ), Alzheimer</p>\n</li>\n<li>\n<p>Bệnh rối loạn vận động như bệnh Parkinson</p>\n</li>\n</ul>\n<p><strong>Quá trình công tác</strong></p>\n<ul>\n<li>\n<p>Trưởng khoa Khám bệnh của Bệnh viện Đa khoa Quốc Tế Thu Cúc</p>\n</li>\n<li>\n<p>Nguyên chủ nhiệm khoa thần kinh, Bệnh viện Hữu Nghị Việt Xô (Nay là bệnh viện Hữu Nghị)</p>\n</li>\n</ul>\n<p><strong>Quá trình đào tạo</strong></p>\n<ul>\n<li>\n<p>Tiến sĩ y khoa - Đại học Y Hà Nội.</p>\n</li>\n<li>\n<p>Thạc sĩ Y khoa - Đại học Sydney, Australia</p>\n</li>\n<li>\n<p>Bác sĩ chuyên khoa thần kinh hệ dài hạn - Đại học Y Hà Nội</p>\n</li>\n</ul>\n<p><strong>Tham gia các chuyên đề sức khỏe</strong></p>\n<ul>\n<li>Tham gia chương trình tư vấn sức khỏe trên truyền hình như Khỏe thật đơn giản (VTV2)</li>\n</ul>\n','**Thầy thuốc ưu tú, Tiến sĩ, Bác sĩ Nguyễn Văn Doanh**\n* Bác sĩ có 40 năm kinh nghiệm làm việc chuyên khoa Nội Thần kinh\n\n* Bác sĩ điều trị hiệu quả các bệnh lý nội khoa, thần kinh phổ biến hiện nay như: đau nửa đầu, rối loạn tiền đình, các rối loạn giấc ngủ, các bệnh về sa sút trí tuệ, bệnh động kinh ở người lớn và trẻ em và nhiều bệnh lý thần kinh khác\n\n* Nguyên chủ nhiệm khoa thần kinh, Bệnh viện Hữu Nghị Việt Xô\n\n**Khám và điều trị**\n* Các bệnh đau đầu: Chứng đau nửa đầu, đau đầu căn nguyên mạch máu, đau đầu mạn tính hàng ngày,..\n* Bệnh đau vai gáy do thoái hóa cột sống cổ, thoát vị đĩa đệm cột sống cổ, …\n\n* Đau thắt lưng hông do thoái hóa, thoát vị, đau do viêm khớp cùng chậu…\n\n* Rối loạn tiền đình\n\n\n* Điều trị chóng mặt do thiếu máu não\n\n* Tư vấn và điều trị các bệnh lý rối loạn về giấc ngủ: mất ngủ cấp tính hoặc mạn tính\n\n* Liệt dây 7 ngoại vi: Viêm các dây thần kinh sọ não và các dây thần kinh ngoại vi khác như hội chứng ống cổ tay, đau vai khuỷu tay do chơi thể thao\n\n* Liệt nửa người do nhồi máu não\n\n* Các bệnh lý về sa sút trí tuệ: Suy giảm nhận thức nhẹ, suy giảm trí nhớ, sa sút trí tuệ nguyên nhân mạch máu (sa sút trí tuệ sau đột quỵ), Alzheimer\n\n* Bệnh rối loạn vận động như bệnh Parkinson\n\n**Quá trình công tác**\n* Trưởng khoa Khám bệnh của Bệnh viện Đa khoa Quốc Tế Thu Cúc\n\n* Nguyên chủ nhiệm khoa thần kinh, Bệnh viện Hữu Nghị Việt Xô (Nay là bệnh viện Hữu Nghị)\n\n**Quá trình đào tạo**\n* Tiến sĩ y khoa - Đại học Y Hà Nội.\n\n* Thạc sĩ Y khoa - Đại học Sydney, Australia\n\n* Bác sĩ chuyên khoa thần kinh hệ dài hạn - Đại học Y Hà Nội\n\n**Tham gia các chuyên đề sức khỏe**\n* Tham gia chương trình tư vấn sức khỏe trên truyền hình như Khỏe thật đơn giản (VTV2)','Bác sĩ có 40 năm kinh nghiệm làm việc chuyên khoa Nội Thần kinh\nBác sĩ điều trị hiệu quả các bệnh lý nội khoa, thần kinh phổ biến hiện nay như: đau nửa đầu, rối loạn tiền đình, các rối loạn giấc ngủ, các bệnh về sa sút trí tuệ, bệnh động kinh ở người lớn và trẻ em và nhiều bệnh lý thần kinh khác \nNguyên chủ nhiệm khoa thần kinh, Bệnh viện Hữu Nghị Việt Xô'),(4,8,3,5,'PRI7','PRO1','PAY3','','','Có hỗ trợ bảo hiểm',0,'2026-04-07 10:33:28','2026-04-07 10:33:28','<p><strong>Giáo sư, Tiến sĩ, Bác sĩ Hà Văn Quyết</strong></p>\n<ul>\n<li>\n<p>Chuyên ngành Ngoại – Phẫu thuật Nội soi Tiêu hóa, Ổ bụng &amp; các bệnh lý hậu môn, trực tràng</p>\n</li>\n<li>\n<p>Nguyên Chủ nhiệm Bộ môn Ngoại - Đại học Y Hà Nội</p>\n</li>\n<li>\n<p>Nguyên Giám đốc Bệnh viện Đại học Y Hà Nội</p>\n</li>\n<li>\n<p>Nguyên Phó Giám đốc Bệnh viện Việt Đức</p>\n</li>\n<li>\n<p>Nhiều năm kinh nghiệm trong việc điều trị các bệnh lý mạn tính như viêm đại tràng, hội chứng ruột kích thích, viêm dạ dày HP tái phát,...</p>\n</li>\n<li>\n<p>Trực tiếp thực hiện các kỹ thuật nội soi bao gồm nội soi dạ dày, đại tràng</p>\n</li>\n<li>\n<p>Bác sĩ dành thời gian để giải thích rõ tình trạng bệnh và phác đồ điều trị, giúp người bệnh an tâm và hiểu rõ quá trình chăm sóc sức khỏe</p>\n</li>\n</ul>\n<p><strong>Khám và điều trị</strong></p>\n<ul>\n<li>\n<p>Giáo sư nhận khám, điều trị các bệnh lý khó về Tiêu hóa, hậu môn, trực tràng, gan mật.</p>\n</li>\n<li>\n<p>Trực tiếp tiến hành Nội soi tiêu hóa, dạ dày, đại tràng</p>\n</li>\n<li>\n<p>Khám, Nội soi, Xét nghiệm sàng lọc ung thư đại trực tràng</p>\n</li>\n<li>\n<p>Khám, Nội soi, Xét nghiệm sàng lọc ung thư dạ dày</p>\n</li>\n<li>\n<p>Khám, Nội soi, Xét nghiệm sàng lọc bệnh lý ung thư đường tiêu hóa</p>\n</li>\n<li>\n<p>Khám, Nội soi, tư vấn điều trị bệnh lý Hậu môn, Bệnh Trĩ Nội, Trĩ Ngoại.</p>\n</li>\n</ul>\n<p><strong>Quá trình Đào tạo</strong></p>\n<ul>\n<li>\n<p>Tốt nghiệp Bác sĩ Đa khoa, Đại học Y Hà Nội.</p>\n</li>\n<li>\n<p>Bác sĩ Nội trú tại các bệnh viện ở Paris, Cộng hòa Pháp</p>\n</li>\n<li>\n<p>Thực tập sinh khoa Tiêu hóa trường Đại học Tokai, Nhật Bản</p>\n</li>\n<li>\n<p>Tu nghiệp về chuyên khoa Tiêu hóa tại Mỹ, Singapore, Hàn Quốc</p>\n</li>\n</ul>\n<p><strong>Sách và các công trình nghiên cứu, báo cáo khoa học</strong></p>\n<ul>\n<li>\n<p>Chủ biên nhiều bộ sách giáo khoa về Ngoại khoa phẫu thuật tiêu hóa và chuyên sâu về tiêu hóa.</p>\n</li>\n<li>\n<p>Tham gia các đề tài nghiên cứu khoa học về ung thư dạ dày, đại trực tràng; các chủ đề về bệnh lý tụy; các loại phẫu thuật nội soi, nội soi can thiệp; bệnh lý về hậu môn trực tràng.</p>\n</li>\n</ul>\n<p><strong>Thành viên các Hội khoa học, tổ chức chuyên môn</strong></p>\n<ul>\n<li>\n<p>Nguyên Tổng thư kí Hội Ngoại khoa Việt Nam</p>\n</li>\n<li>\n<p>Phó Chủ tịch Hội Khoa học về Hậu môn trực tràng</p>\n</li>\n</ul>\n<p>**Tham gia các chuyên đề sức khỏe **</p>\n<ul>\n<li>\n<p>Ban biên tập Tạp chí Y học thực hành</p>\n</li>\n<li>\n<p>Ban biên tập Tạp chí Ngoại khoa</p>\n</li>\n<li>\n<p>Ban biên tập Tạp chí Hậu môn Trực tràng</p>\n</li>\n</ul>\n','**Giáo sư, Tiến sĩ, Bác sĩ Hà Văn Quyết**\n* Chuyên ngành Ngoại – Phẫu thuật Nội soi Tiêu hóa, Ổ bụng & các bệnh lý hậu môn, trực tràng\n\n* Nguyên Chủ nhiệm Bộ môn Ngoại - Đại học Y Hà Nội\n\n* Nguyên Giám đốc Bệnh viện Đại học Y Hà Nội\n\n* Nguyên Phó Giám đốc Bệnh viện Việt Đức\n\n* Nhiều năm kinh nghiệm trong việc điều trị các bệnh lý mạn tính như viêm đại tràng, hội chứng ruột kích thích, viêm dạ dày HP tái phát,...\n\n* Trực tiếp thực hiện các kỹ thuật nội soi bao gồm nội soi dạ dày, đại tràng\n\n* Bác sĩ dành thời gian để giải thích rõ tình trạng bệnh và phác đồ điều trị, giúp người bệnh an tâm và hiểu rõ quá trình chăm sóc sức khỏe\n\n**Khám và điều trị**\n* Giáo sư nhận khám, điều trị các bệnh lý khó về Tiêu hóa, hậu môn, trực tràng, gan mật.\n\n* Trực tiếp tiến hành Nội soi tiêu hóa, dạ dày, đại tràng\n\n* Khám, Nội soi, Xét nghiệm sàng lọc ung thư đại trực tràng\n\n* Khám, Nội soi, Xét nghiệm sàng lọc ung thư dạ dày\n\n* Khám, Nội soi, Xét nghiệm sàng lọc bệnh lý ung thư đường tiêu hóa\n\n* Khám, Nội soi, tư vấn điều trị bệnh lý Hậu môn, Bệnh Trĩ Nội, Trĩ Ngoại.\n\n**Quá trình Đào tạo**\n* Tốt nghiệp Bác sĩ Đa khoa, Đại học Y Hà Nội.\n\n* Bác sĩ Nội trú tại các bệnh viện ở Paris, Cộng hòa Pháp\n\n* Thực tập sinh khoa Tiêu hóa trường Đại học Tokai, Nhật Bản\n\n* Tu nghiệp về chuyên khoa Tiêu hóa tại Mỹ, Singapore, Hàn Quốc\n\n**Sách và các công trình nghiên cứu, báo cáo khoa học**\n* Chủ biên nhiều bộ sách giáo khoa về Ngoại khoa phẫu thuật tiêu hóa và chuyên sâu về tiêu hóa.\n\n* Tham gia các đề tài nghiên cứu khoa học về ung thư dạ dày, đại trực tràng; các chủ đề về bệnh lý tụy; các loại phẫu thuật nội soi, nội soi can thiệp; bệnh lý về hậu môn trực tràng.\n\n**Thành viên các Hội khoa học, tổ chức chuyên môn**\n* Nguyên Tổng thư kí Hội Ngoại khoa Việt Nam\n\n* Phó Chủ tịch Hội Khoa học về Hậu môn trực tràng\n\n**Tham gia các chuyên đề sức khỏe **\n* Ban biên tập Tạp chí Y học thực hành\n\n* Ban biên tập Tạp chí Ngoại khoa\n\n* Ban biên tập Tạp chí Hậu môn Trực tràng','Chuyên gia hơn 40 năm kinh nghiệm trong lĩnh vực bệnh lý Tiêu hóa\nNhiều năm kinh nghiệm trong việc điều trị các bệnh lý mạn tính như viêm đại tràng, hội chứng ruột kích thích, viêm dạ dày HP tái phát,...\nNguyên Giám đốc Bệnh viện Đại học Y Hà Nội'),(5,9,3,2,'PRI2','PRO1','PAY3','','','',0,'2026-04-07 10:38:31','2026-04-07 10:38:31','<ul>\n<li></li>\n</ul>\n<p><strong>Bác sĩ Thẩm Hoàng Hải</strong></p>\n<ul>\n<li>\n<p>Có nhiều kinh nghiệm trong lĩnh vực khám, chữa bệnh chuyên khoa Nội – Nội soi tiêu hóa</p>\n</li>\n<li>\n<p>Trưởng đơn nguyên Nội soi tiêu hóa – Khoa Thăm dò Chức năng - Nội soi tiêu hóa, Bệnh viện ĐKQT Thu Cúc</p>\n</li>\n</ul>\n<p><strong>Khám và điều trị:</strong></p>\n<ul>\n<li>\n<p>Các bệnh lý nội tiêu hóa</p>\n</li>\n<li>\n<p>Đau dạ dày</p>\n</li>\n<li>\n<p>Trào ngược dạ dày - thực quản</p>\n</li>\n<li>\n<p>Viêm hang vị dạ dày</p>\n</li>\n<li>\n<p>Viêm, loét dạ dày</p>\n</li>\n<li>\n<p>Viêm, loét tá tràng</p>\n</li>\n<li>\n<p>Đau thượng vị</p>\n</li>\n<li>\n<p>Khó nuốt</p>\n</li>\n<li>\n<p>Khó tiêu...</p>\n</li>\n</ul>\n<p><strong>Các bệnh lý về ruột</strong></p>\n<ul>\n<li>\n<p>Hội chứng ruột kích thích</p>\n</li>\n<li>\n<p>Bệnh lý không dung nạp lactose</p>\n</li>\n<li>\n<p>Viêm đại tràng</p>\n</li>\n<li>\n<p>Polyp, ung thư đại tràng…</p>\n</li>\n<li>\n<p>Đi ngoài ra máu</p>\n</li>\n<li>\n<p>Nứt kẽ hậu môn, đại tiện khó...</p>\n</li>\n</ul>\n<p><strong>Quá trình công tác</strong></p>\n<ul>\n<li>\n<p>Trưởng đơn nguyên Nội soi tiêu hóa – Khoa Thăm dò Chức năng - Nội soi tiêu hóa, Bệnh viện ĐKQT Thu Cúc</p>\n</li>\n<li>\n<p>Bác sĩ Nội soi tiêu hóa Bệnh viện Đa khoa Hồng Ngọc</p>\n</li>\n</ul>\n<p><strong>Quá trình đào tạo</strong></p>\n<ul>\n<li>\n<p>Tốt nghiệp định hướng Nội khoa tại Đại học Y Hà Nội</p>\n</li>\n<li>\n<p>Tốt nghiệp Bác sĩ Đa khoa tại Đại học Y Hà Nội</p>\n</li>\n</ul>\n','* \n\n**Bác sĩ Thẩm Hoàng Hải**\n* Có nhiều kinh nghiệm trong lĩnh vực khám, chữa bệnh chuyên khoa Nội – Nội soi tiêu hóa\n\n* Trưởng đơn nguyên Nội soi tiêu hóa – Khoa Thăm dò Chức năng - Nội soi tiêu hóa, Bệnh viện ĐKQT Thu Cúc\n\n**Khám và điều trị:** \n* Các bệnh lý nội tiêu hóa\n\n* Đau dạ dày\n\n* Trào ngược dạ dày - thực quản\n\n* Viêm hang vị dạ dày\n\n* Viêm, loét dạ dày\n\n* Viêm, loét tá tràng\n\n* Đau thượng vị\n\n* Khó nuốt\n\n* Khó tiêu...\n\n**Các bệnh lý về ruột**\n\n* Hội chứng ruột kích thích\n\n* Bệnh lý không dung nạp lactose\n\n* Viêm đại tràng\n\n* Polyp, ung thư đại tràng…\n\n* Đi ngoài ra máu\n\n* Nứt kẽ hậu môn, đại tiện khó...\n\n**Quá trình công tác**\n* Trưởng đơn nguyên Nội soi tiêu hóa – Khoa Thăm dò Chức năng - Nội soi tiêu hóa, Bệnh viện ĐKQT Thu Cúc\n\n* Bác sĩ Nội soi tiêu hóa Bệnh viện Đa khoa Hồng Ngọc\n\n**Quá trình đào tạo**\n* Tốt nghiệp định hướng Nội khoa tại Đại học Y Hà Nội\n\n* Tốt nghiệp Bác sĩ Đa khoa tại Đại học Y Hà Nội','Có nhiều kinh nghiệm trong lĩnh vực khám, chữa bệnh chuyên khoa Nội – Nội soi tiêu hóa\nTrưởng đơn nguyên Nội soi tiêu hóa – Khoa Thăm dò Chức năng - Nội soi tiêu hóa, Bệnh viện ĐKQT Thu Cúc'),(6,10,4,6,'PRI4','PRO2','PAY3','','','Khong hỗ trợ bảo hiểm',0,'2026-04-07 10:40:43','2026-04-07 10:40:43','<p><strong>Bác sĩ Châu Khắc Tuấn</strong></p>\n<ul>\n<li>\n<p>Bác sĩ Tim mạch tại Hệ thống Bệnh viện Đa khoa Hồng Đức III</p>\n</li>\n<li>\n<p>Nhiều năm kinh nghiệm lâm sàng Nội tổng quát và Tim mạch</p>\n</li>\n<li>\n<p>Bác sĩ nhận khám mọi độ tuổi</p>\n</li>\n</ul>\n<p><strong>Nhận khám và điều trị</strong></p>\n<ul>\n<li>\n<p>Khám, tư vấn, điều trị chuyên sâu các bệnh về Tim mạch</p>\n</li>\n<li>\n<p>Các bệnh lý Nội Tim mạch</p>\n</li>\n<li>\n<p>Bệnh van tim</p>\n</li>\n<li>\n<p>Bệnh cơ tim</p>\n</li>\n<li>\n<p>Rối loạn nhịp tim</p>\n</li>\n<li>\n<p>Khám bệnh mạch máu ngoại biên</p>\n</li>\n<li>\n<p>Tư vấn, phát hiện sớm và phòng ngừa các bệnh lý tim mạch</p>\n</li>\n</ul>\n<p><strong>Quá trình công tác</strong></p>\n<ul>\n<li>Bác sĩ Tim mạch tại Bệnh viện Đa khoa Hồng Đức III</li>\n</ul>\n<p><strong>Chứng chỉ trong nước hoặc nước ngoài</strong></p>\n<ul>\n<li>Chứng chỉ hành nghề chuyên khoa nội do Sở Y tế TPHCM cấp</li>\n</ul>\n','**Bác sĩ Châu Khắc Tuấn**\n* Bác sĩ Tim mạch tại Hệ thống Bệnh viện Đa khoa Hồng Đức III\n\n* Nhiều năm kinh nghiệm lâm sàng Nội tổng quát và Tim mạch\n\n* Bác sĩ nhận khám mọi độ tuổi\n\n**Nhận khám và điều trị**\n* Khám, tư vấn, điều trị chuyên sâu các bệnh về Tim mạch\n\n* Các bệnh lý Nội Tim mạch\n\n* Bệnh van tim\n\n* Bệnh cơ tim\n\n* Rối loạn nhịp tim\n\n* Khám bệnh mạch máu ngoại biên\n\n* Tư vấn, phát hiện sớm và phòng ngừa các bệnh lý tim mạch\n\n**Quá trình công tác**\n* Bác sĩ Tim mạch tại Bệnh viện Đa khoa Hồng Đức III\n\n**Chứng chỉ trong nước hoặc nước ngoài**\n* Chứng chỉ hành nghề chuyên khoa nội do Sở Y tế TPHCM cấp','Bác sĩ Tim mạch tại Hệ thống Bệnh viện Đa khoa Hồng Đức III\nNhiều năm kinh nghiệm lâm sàng Nội tổng quát và Tim mạch\nBác sĩ nhận khám mọi độ tuổi'),(7,11,4,5,'PRI3','PRO2','PAY3','','','Hỗ trợ bảo hiểm',0,'2026-04-07 10:43:10','2026-04-07 10:43:10','<p><strong>Thạc sĩ, Bác sĩ Bùi Xuân Nga</strong></p>\n<ul>\n<li>\n<p>Hơn 20 năm kinh nghiệm khám và điều trị các bệnh lý về Nội Tim mạch</p>\n</li>\n<li>\n<p>Từng công tác tại khoa Nội Tim mạch, Bệnh viện Đại học Y Dược TP.HCM</p>\n</li>\n<li>\n<p>Bác sĩ khoa Nội Tim mạch, Bệnh viện Quốc tế City</p>\n</li>\n</ul>\n<p><strong>Khám và điều trị</strong></p>\n<p>Bác sĩ nhận khám và điều trị bệnh lý về:</p>\n<ul>\n<li>\n<p>Bệnh mạch vành: đau ngực trái, khó thở</p>\n</li>\n<li>\n<p>Nhồi máu cơ tim: đau ngực trái, khó thở</p>\n</li>\n<li>\n<p>Xơ vữa mạch máu: đau ngực, đau chân khi đi lại, tai biến mạch não</p>\n</li>\n<li>\n<p>Hẹp động mạch cảnh: đau đầu, chóng mặt, tai biến mạch não</p>\n</li>\n<li>\n<p>Đột quỵ: yếu tay chân, liệt mặt</p>\n</li>\n<li>\n<p>Tăng huyết áp: huyết áp cao, đau ngực, đau đầu</p>\n</li>\n<li>\n<p>Bệnh tim do đái tháo đường: đau ngực, khó thở</p>\n</li>\n<li>\n<p>Rối loạn lipid máu: tăng lipid máu, bệnh mạch vành, đột quỵ</p>\n</li>\n</ul>\n<p><strong>Quá trình công tác</strong></p>\n<ul>\n<li>\n<p>Bác sĩ khoa Nội Tim mạch, Bệnh viện Quốc tế City (2013 - nay)</p>\n</li>\n<li>\n<p>Bác sĩ điều trị khoa Nội Tim Mạch, Bệnh viện Đại học Y Dược TP.HCM (2005 - 2013)</p>\n</li>\n</ul>\n<p><strong>Quá trình đào tạo</strong></p>\n<ul>\n<li>\n<p>Tốt nghiệp Thạc sĩ chuyên ngành Lão khoa, Đại học Y dược TP.HCM (2012)</p>\n</li>\n<li>\n<p>Tốt Nghiệp Bác sĩ Đa khoa Đại học Y dược TP.HCM (2001)</p>\n</li>\n</ul>\n','**Thạc sĩ, Bác sĩ Bùi Xuân Nga**\n* Hơn 20 năm kinh nghiệm khám và điều trị các bệnh lý về Nội Tim mạch\n\n* Từng công tác tại khoa Nội Tim mạch, Bệnh viện Đại học Y Dược TP.HCM\n\n* Bác sĩ khoa Nội Tim mạch, Bệnh viện Quốc tế City\n\n**Khám và điều trị**\n\nBác sĩ nhận khám và điều trị bệnh lý về:\n\n\n* Bệnh mạch vành: đau ngực trái, khó thở\n\n* Nhồi máu cơ tim: đau ngực trái, khó thở\n\n* Xơ vữa mạch máu: đau ngực, đau chân khi đi lại, tai biến mạch não\n\n* Hẹp động mạch cảnh: đau đầu, chóng mặt, tai biến mạch não\n\n* Đột quỵ: yếu tay chân, liệt mặt\n\n* Tăng huyết áp: huyết áp cao, đau ngực, đau đầu\n\n* Bệnh tim do đái tháo đường: đau ngực, khó thở\n\n* Rối loạn lipid máu: tăng lipid máu, bệnh mạch vành, đột quỵ\n\n**Quá trình công tác**\n* Bác sĩ khoa Nội Tim mạch, Bệnh viện Quốc tế City (2013 - nay)\n\n* Bác sĩ điều trị khoa Nội Tim Mạch, Bệnh viện Đại học Y Dược TP.HCM (2005 - 2013)\n\n**Quá trình đào tạo**\n* Tốt nghiệp Thạc sĩ chuyên ngành Lão khoa, Đại học Y dược TP.HCM (2012)\n\n* Tốt Nghiệp Bác sĩ Đa khoa Đại học Y dược TP.HCM (2001)','Hơn 20 năm kinh nghiệm khám và điều trị các bệnh lý về Nội Tim mạch\nTừng công tác tại khoa Nội Tim mạch, Bệnh viện Đại học Y Dược TP.HCM\nBác sĩ khoa Nội Tim mạch, Bệnh viện Quốc tế City');
